// Package enginepb contains the Go bindings generated from
// proto/emulator.proto. The bindings are produced by `buf generate`
// (see ../../buf.gen.yaml) and the generated files in this directory
// (`emulator.pb.go`, `emulator_grpc.pb.go`) are kept in version
// control so consumers can `go build` without first running codegen.
//
// To regenerate after a proto change, run `task proto:gen` from the
// repository root.
package enginepb
